x;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* === PARTNER ECONOMICS HERO === */\n.econ-hero-section{background:linear-gradient(135deg,#000432 0%,#000864 50%,#001080 100%);padding:140px 24px 100px;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.econ-hero-section::before{content:\'\';position:absolute;inset:0;background-image:radial-gradient(circle,rgba(255,255,255,0.03) 1.5px,transparent 1.5px);background-size:60px 60px;pointer-events:none;z-index:0}\n.econ-hero-grain::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg viewBox=\'0 0 400 400\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'n\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.9\' numOctaves=\'4\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23n)\'/%3E%3C/svg%3E");opacity:0.03;pointer-events:none;z-index:1}\n.econ-hero-grain{position:absolute;inset:0;z-index:1;opacity:0.16}\n.econ-hero-d-bg{position:absolute;top:auto;right:-10%;bottom:-20%;left:auto;width:60%;min-height:60vh;background:url("data:image/svg+xml;base64,") no-repeat center bottom;background-size:contain;opacity:0.16;pointer-events:none;z-index:0}\n.econ-hero-dot-overlay{position:absolute;inset:0;background-image:radial-gradient(circle,rgba(255,255,255,0.03) 1.5px,transparent 1.5px);background-size:60px 60px;pointer-events:none;z-index:1}\n.econ-hero-inner{max-width:900px;margin:0 auto;position:relative;z-index:3}\n.econ-hero-breadcrumb{font-family:\'Noto Sans\',sans-serif;font-size:14px;color:rgba(255,255,255,0.85);margin-bottom:24px}\n.econ-hero-breadcrumb a{color:rgba(255,255,255,0.85);text-decoration:none;transition:color 0.2s}\n.econ-hero-breadcrumb a:hover{color:#00AFF0}\n.econ-hero-breadcrumb span{margin:0 8px}\n.econ-hero-title{font-family:\'Noto Sans\',sans-serif;font-size:clamp(36px,5vw,52px);font-weight:700;color:#fff;line-height:1.15;margin:0 0 24px;padding:0}\n.econ-hero-hl{color:#4ade80}\n.econ-hero-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:20px;font-weight:400;color:rgba(255,255,255,0.85);line-height:1.7;max-width:700px;margin:0 0 48px;padding:0}\n.econ-hero-proof{display:grid;grid-template-columns:repeat(4,1fr);gap:24px;padding-top:40px;border-top:1px solid rgba(255,255,255,0.1)}\n.econ-hero-proof-item{text-align:center}\n.econ-hero-proof-value{font-family:\'Noto Sans\',sans-serif;font-size:32px;font-weight:700;color:#15803d;display:block;margin-bottom:8px}\n.econ-hero-proof-label{font-family:\'JetBrains Mono\',monospace;font-size:12px;font-weight:500;color:rgba(255,255,255,0.8);text-transform:uppercase;letter-spacing:0.5px}\n@media(max-width:1024px){\n  .econ-hero-section{padding:120px 24px 80px}\n  .econ-hero-proof{grid-template-columns:repeat(2,1fr)}\n}\n@media(max-width:768px){\n  .econ-hero-section{padding:100px 20px 60px}\n  .econ-hero-proof{grid-template-columns:1fr 1fr;gap:16px}\n  .econ-hero-proof-value{font-size:24px}\n}\n@media(prefers-reduced-motion:reduce){.econ-hero-breadcrumb a{transition:none !important}}\n.et_pb_section .econ-hero-proof-label {\n            line-height: 19.2px !important;\n        }\n\n.et_pb_section .econ-hero-proof-value {\n 